(function () {
  if (typeof window === 'undefined') return;
  if (window.initAdSenseSlot) return;

  window.initAdSenseSlot = function (scriptEl) {
    try {
      var ins = null;
      if (
        scriptEl &&
        scriptEl.previousElementSibling &&
        scriptEl.previousElementSibling.classList &&
        scriptEl.previousElementSibling.classList.contains('adsbygoogle')
      ) {
        ins = scriptEl.previousElementSibling;
      }
      if (!ins) return;

      var attempts = 0;
      var maxAttempts = 30;
      var delayMs = 160;

      var tryInit = function () {
        if (!document.body || !document.body.contains(ins)) return;
        if (ins.getAttribute('data-ads-initialized') === '1') return;

        var width = ins.offsetWidth || ins.clientWidth || 0;
        if (!width && ins.getBoundingClientRect) {
          width = ins.getBoundingClientRect().width || 0;
        }

        if (width > 0) {
          (window.adsbygoogle = window.adsbygoogle || []).push({});
          ins.setAttribute('data-ads-initialized', '1');
          return;
        }

        attempts += 1;
        if (attempts < maxAttempts) {
          setTimeout(tryInit, delayMs);
        }
      };

      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', tryInit, { once: true });
      } else {
        tryInit();
      }
    } catch (e) {
      // Silenciar errores de inicializacion de ads para no romper UX.
    }
  };
})();
